import React, { useState } from 'react';

const ConceptTree = ({ initialData }) => {
  const [tree, setTree] = useState(initialData);
  const [selectedNode, setSelectedNode] = useState(null);

  const handleNodeClick = (node) => {
    console.log('Node clicked:', node.name);
    setSelectedNode(node);
  };

  const renderNodes = (nodes) => {
    return nodes.map((node) => (
      <div key={node.id} className="node-item" onClick={() => handleNodeClick(node)}>
        <div className="node-label">{node.name}</div>
        {node.children && node.children.length > 0 && (
          <div className="node-children">
            {renderNodes(node.children)}
          </div>
        )}
      </div>
    ));
  };

  return (
    <div className="tree-container">
      <header className="tree-header">
        <h1>Concept Visualization Tree</h1>
        <p>Current Selection: {selectedNode ? selectedNode.name : 'None'}</p>
      </header>
      <div className="tree-content">
        {tree && tree.length > 0 ? renderNodes(tree) : <p>Empty Tree</p>}
      </div>
      <aside className="details-panel">
        {selectedNode && (
          <div>
            <h3>{selectedNode.name}</h3>
            <p>{selectedNode.description}</p>
          </div>
        )}
      </aside>
      <style>{` 
        .tree-container { display: flex; flex-direction: column; padding: 20px; }
        .node-item { margin-left: 20px; cursor: pointer; border-left: 1px solid #ccc; }
        .node-label:hover { color: #007bff; }
      `}</style>
    </div>
  );
};

export default ConceptTree;
